  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Ethereum Foundation Restructuring Timeline — 2026</text>
  <g font-family="sans-serif">
    <line x1="60" y1="70" x2="60" y2="420" stroke="#3f3f46" stroke-width="2"/>
    <circle cx="60" cy="90" r="7" fill="#71717a"/>
